// Busca credenciais existentes no n8n e cria/atualiza OpenAI e ElevenLabs
const supabaseData = $('Buscar Chaves Supabase').first().json;
const chaveOpenai = supabaseData.chave_openai;
const chaveElevenLabs = supabaseData.chave_elevenlabs;
const baseUrl = $vars.n8nBaseUrl;
const apiKey = $vars.n8nApiKey;

const headers = {
  'X-N8N-API-KEY': apiKey,
  'Content-Type': 'application/json'
};

// Lista credenciais existentes
const listResp = await fetch(`${baseUrl}/api/v1/credentials`, { headers });
const listData = await listResp.json();
const credenciais = listData.data || [];

async function criarOuAtualizar(nome, tipo, dados) {
  const existente = credenciais.find(c => c.name === nome);
  if (existente) {
    const r = await fetch(`${baseUrl}/api/v1/credentials/${existente.id}`, {
      method: 'PATCH',
      headers,
      body: JSON.stringify({ name: nome, data: dados })
    });
    return { acao: 'atualizado', nome, id: existente.id, status: r.status };
  } else {
    const r = await fetch(`${baseUrl}/api/v1/credentials`, {
      method: 'POST',
      headers,
      body: JSON.stringify({ name: nome, type: tipo, data: dados })
    });
    const nova = await r.json();
    return { acao: 'criado', nome, id: nova.id, status: r.status };
  }
}

const resultados = [];

if (chaveOpenai) {
  resultados.push(await criarOuAtualizar('OpenAI Dinâmico', 'openAiApi', { apiKey: chaveOpenai }));
} else {
  resultados.push({ acao: 'ignorado', nome: 'OpenAI Dinâmico', motivo: 'chave não configurada' });
}

if (chaveElevenLabs) {
  resultados.push(await criarOuAtualizar('ElevenLabs Dinâmico', 'elevenLabsApi', { apiKey: chaveElevenLabs }));
} else {
  resultados.push({ acao: 'ignorado', nome: 'ElevenLabs Dinâmico', motivo: 'chave não configurada' });
}

return [{ json: { credenciais_atualizadas: resultados } }];
